-- BRK-10P Lender Communications
CREATE TABLE IF NOT EXISTS public.brokerage_lender_message_templates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trigger_key text NOT NULL UNIQUE, channel text NOT NULL DEFAULT 'email' CHECK (channel IN ('email','dashboard')), subject text, body_md text NOT NULL, status text NOT NULL DEFAULT 'active' CHECK (status IN ('active','inactive')), created_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE public.brokerage_lender_message_templates ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.brokerage_lender_message_outbox (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), deal_id uuid REFERENCES public.deals(id), listing_id uuid REFERENCES public.marketplace_listings(id), claim_id uuid REFERENCES public.marketplace_claims(id), lender_bank_id uuid NOT NULL REFERENCES public.banks(id), trigger_key text NOT NULL, channel text NOT NULL CHECK (channel IN ('email','dashboard')), recipient text, subject text, body text NOT NULL, status text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','sent','failed','suppressed')), attempts integer NOT NULL DEFAULT 0, last_attempt_at timestamptz, sent_at timestamptz, error text, cooldown_key text, metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS brk_lender_outbox_cooldown_idx ON public.brokerage_lender_message_outbox (cooldown_key, created_at DESC);
ALTER TABLE public.brokerage_lender_message_outbox ENABLE ROW LEVEL SECURITY;
INSERT INTO public.brokerage_lender_message_templates (trigger_key, channel, subject, body_md) VALUES ('marketplace_preview_open','email','New SBA deal available','A new SBA deal matching your criteria is available on Buddy Marketplace.'),('claim_window_open','email','Claim window open','The claim window is now open for a matched deal.'),('claim_confirmed','email','Claim confirmed','Your claim has been confirmed.'),('borrower_selected_lender','email','You have been selected','The borrower selected your bank. Full package access is being granted.'),('package_access_granted','email','Package access granted','You now have full access to the loan package.'),('clear_to_close','email','Clear to close','All conditions satisfied. Deal is clear to close.'),('funding_verified','email','Funding verified','Funding verified. Referral fee recorded.') ON CONFLICT (trigger_key) DO NOTHING;
